return ['domain'=>'agnosis','plural-forms'=>'nplurals=2; plural=n != 1;','language'=>'nl_NL','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-16T07:59+00:00','po-revision-date'=>'2026-07-12 18:00+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'Kunst die uit de vergetelheid opbloeit. Mail je kunst, AI polijst het, de wereld ziet het. Een gratis, federaal publicatienetwerk voor onafhankelijke kunstenaars.','Agnosis requires PHP %s or higher.'=>'Agnosis vereist PHP %s of hoger.','Agnosis requires WordPress %s or higher.'=>'Agnosis vereist WordPress %s of hoger.','Filter by medium'=>'Filter op medium','All'=>'Alles','Enlarged image'=>'Vergrote afbeelding','Featured'=>'Uitgelicht','Enlarge'=>'Vergroten','Gallery pages'=>'Galerijpagina\'s','Prev'=>'Vorige','Next'=>'Volgende','Contact Messages'=>'Contactberichten','No contact messages yet.'=>'Er zijn nog geen contactberichten.','No messages match this filter.'=>'Er komen geen berichten overeen met deze filter.','#'=>'#','Artist'=>'Kunstenaar','From'=>'Van','Message'=>'Bericht','Status'=>'Status','Received'=>'Ontvangen','Actions'=>'Acties','(deleted artist #%d)'=>'(verwijderde kunstenaar #%d)','You do not have permission to perform this action.'=>'Je hebt geen toestemming om deze actie uit te voeren.','Message deleted.'=>'Bericht verwijderd.','All statuses'=>'Alle statussen','Sent'=>'Verzonden','Rejected'=>'Geweigerd','Filter'=>'Filter','Reset'=>'Opnieuw instellen','Page %1$d of %2$d'=>'Pagina %1$d van %2$d','Previous'=>'Vorige','Delete this message?'=>'Dit bericht verwijderen?','Delete'=>'Verwijderen','just now'=>'zojuist','%dm ago'=>'%dm geleden','%dh ago'=>'%du geleden','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'Nieuwsbrief','Agnosis Inbox'=>'Agnosis Inbox','Inbox'=>'Inbox','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'Er zijn nog geen berichten in de wachtrij. Klik op "Inbox ophalen" om berichten uit je IMAP-account op te halen.','No queue rows match this filter.'=>'Er komen geen rijen in de wachtrij overeen met deze filter.','Subject'=>'Onderwerp','Endpoint'=>'Eindpunt','Files'=>'Bestanden','Error'=>'Fout','unregistered sender'=>'on geregistreerde afzender','Old row — delete and re-poll to preview'=>'Oude rij — verwijderen en opnieuw pollen om een preview te zien','Attachment viewer'=>'Bijlageviewer','Close'=>'Sluiten','Queue row deleted. Poll Inbox to re-fetch the message.'=>'Wachtrijregel verwijderd. Poll Inbox om het bericht opnieuw op te halen.','Queue #%d sent to pipeline. Check back in a few seconds.'=>'Wachtrij #%d verzonden naar de pijplijn. Kijk over een paar seconden nog eens.','Poll complete. %d new message(s) added to the queue.'=>'Polling voltooid. %d nieuw(e) bericht(en) toegevoegd aan de wachtrij.','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'Opnieuw forceren: %1$d rij(en) gereset, %2$d nieuw(e) bericht(en) toegevoegd aan de wachtrij.','Processed %d pending item(s).'=>'%d openstaand(e) item(s) verwerkt.','Pending'=>'Openstaand','Processing'=>'Bezig met verwerken','Published'=>'Gepubliceerd','Failed'=>'Mislukt','Skipped'=>'Overgeslagen','All reasons'=>'Alle redenen','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'%1$d bericht van een niet-geregistreerde afzender is verborgen in deze weergave. <a href="%2$s">Bekijk het</a>.' . "\0" . '%1$d berichten van niet-geregistreerde afzenders zijn verborgen in deze weergave. <a href="%2$s">Bekijk ze</a>.','Poll Inbox'=>'Postvak binnenhalen','Force Reprocess'=>'Opnieuw forceren','Process All Pending'=>'Alle openstaande items verwerken','Goodbye'=>'Tot ziens','Community'=>'Community','Bounce'=>'Bounce','Awaiting Review'=>'Wacht op beoordeling','Live'=>'Live','Processed'=>'Verwerkt','Member Removed'=>'Lid verwijderd','Broadcast Sent'=>'Verstuurde broadcast','Bounced (too long)'=>'Gebounced (te lang)','Handled'=>'Afgehandeld','Process'=>'Verwerken','View Post'=>'Bericht bekijken','Reprocess'=>'Opnieuw verwerken','Running…'=>'Bezig…','Delete this queue row?'=>'Deze wachtrijregel verwijderen?','Configuration'=>'Configuratie','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'Opnieuw forceren voltooid. %1$d wachtrijregel(en) gereset, %2$d nieuw(e) bericht(en) toegevoegd aan de wachtrij. Klik op "Openstaande wachtrij verwerken" om de AI-pijplijn uit te voeren.','Log cleared.'=>'Log gewist.','Debug files cleared. %d file was removed.'=>'Debugbestanden gewist. %d bestand is verwijderd.' . "\0" . 'Debugbestanden gewist. %d bestanden zijn verwijderd.','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'Cache voor termvertaling gewist. Termen worden de volgende keer dat ze nodig zijn opnieuw vertaald.','Processed %d pending queue item(s). Check the Logs tab for details.'=>'%d openstaande wachtrij-item(s) verwerkt. Kijk in het tabblad Logs voor details.','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'Polling voltooid. %d nieuw(e) bericht(en) toegevoegd aan de wachtrij. Kijk in het tabblad Logs en klik daarna op Openstaande wachtrij verwerken.','Applicant admitted. A welcome email has been sent.'=>'Aanvrager toegelaten. Er is een welkomstmail verstuurd.','Could not admit — the application may no longer be pending.'=>'Toelaten kon niet — de aanvraag is mogelijk niet meer in behandeling.','Application rejected.'=>'Aanvraag afgewezen.','Could not reject — the application may no longer be pending.'=>'Afwijzen kon niet — de aanvraag is mogelijk niet meer in behandeling.','Artist suspended. A notification email has been sent.'=>'Artist geschorst. Er is een melding per e-mail verstuurd.','Could not suspend the artist — they may no longer be active.'=>'Kunnen de artist niet schorsen — mogelijk is die niet meer actief.','Artist permanently deleted. Their account and all content have been removed.'=>'Artist permanent verwijderd. Hun account en alle content zijn verwijderd.','Could not delete the artist — please try again.'=>'Kunnen de artist niet verwijderen — probeer het opnieuw.','Community removal vote opened. All artists have been emailed.'=>'Stem voor verwijdering uit de community geopend. Alle artists zijn gemaild.','Could not open a removal vote — one may already be active for this artist.'=>'Kon geen verwijderingsstemming openen — er is mogelijk al een actieve voor deze artist.','Issue prepared and queued — it will go out over the next few cron cycles.'=>'Issue voorbereid en in de wachtrij gezet — het wordt verstuurd in de komende cron-cycli.','Could not start this issue — a previous one may still be sending.'=>'Kon dit issue niet starten — een vorige wordt mogelijk nog verstuurd.','Test email sent — check the inbox you sent it to.'=>'Testmail verstuurd — check de inbox waar je hem naartoe hebt gestuurd.','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'Kon de testmail niet versturen — controleer het adres en de uitgaande mailconfiguratie van je site.','Invitation sent.'=>'Uitnodiging verstuurd.','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'Kon de uitnodiging niet versturen — controleer het adres en de uitgaande mailconfiguratie van je site.','Test invitation sent — check the inbox you sent it to.'=>'Testuitnodiging verstuurd — check de inbox waar je hem naartoe hebt gestuurd.','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'Kon de testuitnodiging niet versturen — controleer het adres en de uitgaande mailconfiguratie van je site.','Test email sent — check whether it lands in your inbox or your spam folder.'=>'Testmail verstuurd — kijk of hij in je inbox of in je spamfolder terechtkomt.','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'Mislukte ontvangers teruggezet naar in behandeling — ze worden opnieuw geprobeerd in de komende cron-cycli.','No failed recipients to retry for this newsletter.'=>'Geen mislukte ontvangers om opnieuw te proberen voor deze nieuwsbrief.','Art blooming out of oblivion'=>'Kunst die opbloeit uit vergetelheid','Save Changes'=>'Wijzigingen opslaan','Members'=>'Leden','Rules'=>'Regels','General'=>'Algemeen','Email Inbox'=>'E-mailinbox','AI Providers'=>'AI-aanbieders','Behavior'=>'Gedrag','Network'=>'Netwerk','Commerce'=>'Commercie','Logs'=>'Logs','— None (inline message only) —'=>'— Geen (alleen inline bericht) —','Reset to default'=>'Terugzetten naar standaard','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'Vervangt de tekst hierboven door de ingebouwde standaard van de plugin — klik hieronder op Wijzigingen opslaan om het te behouden.','Select Image'=>'Afbeelding selecteren','Remove'=>'Verwijderen','Base domain'=>'Basisdomein','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'Rootdomein voor subdomeinen van kunstenaars, bijv. agnosis.art. Elke kunstenaar is bereikbaar op nicename.{base_domain}. Vereist een wildcard-DNS-record (*.{base_domain}) dat naar deze server verwijst. Laat leeg om subdomeinroutering uit te schakelen.','Debug logging'=>'Debuglogging','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'Schrijft ruwe diagnostische dumps van de e-mailintakepipeline (berichtstructuur, MIME-detectie van bijlagen, mediaconversie, aanmaak van berichten) naar een aparte debugmap — veel meer detail dan het Logs-tabblad bewaart, om precies te achterhalen waar een inzending is afgewezen of verloren gegaan. Zet uit zodra je hebt wat je nodig hebt; bestanden kunnen zich snel opstapelen. Kan ook geforceerd worden vanuit wp-config.php met `define( \'AGNOSIS_DEBUG\', true );`, waarmee deze schakelaar wordt overschreven. Zie het paneel Debugbestanden hieronder voor de maplocatie en een knop om bestanden te wissen.','Debug file retention (days)'=>'Bewaartermijn debugbestanden (dagen)','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'Debugdumps ouder dan dit worden definitief verwijderd door de dagelijkse opschoning — automatisch, ongeacht of debuglogging momenteel aan staat, zodat bestanden die overblijven van een eerdere debugsessie niet eindeloos blijven hangen. Een dump is een volledige ruwe kopie van een e-mail van een kunstenaar, dus dit staat standaard korter ingesteld dan de bewaartermijn van inbox/wachtrij hierboven. Standaard: 14 dagen.','Preset biography title'=>'Vooringestelde biografietitel','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'Als dit is ingesteld, gebruikt de biografiepagina van elke kunstenaar precies deze titel in plaats van hun eigen titel, ongeacht wat de kunstenaar heeft ingestuurd, op hun goedkeuringsformulier heeft aangepast of later op hun gepubliceerde pagina heeft gewijzigd. Laat leeg om de eigen titel van elke kunstenaar te blijven gebruiken (de standaard). Wordt exact weergegeven zoals hier getypt op elke taalversie van een biografiepagina — niet per taal machinaal vertaald. Zie hieronder "Naam van de kunstenaar opnemen in vooringestelde titel".','Include artist\'s name in preset title'=>'Naam van de kunstenaar opnemen in vooringestelde titel','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'Wanneer de vooringestelde titel hierboven is ingesteld, wordt de WordPress-weergavenaam van de kunstenaar eraan toegevoegd (bijv. "Ontmoet de kunstenaar — Jane Doe"). Heeft geen effect zolang de vooringestelde titel leeg is.','Cloudflare Turnstile site key'=>'Site-sleutel voor Cloudflare Turnstile','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'Uit je Cloudflare Turnstile-widget (dash.cloudflare.com → Turnstile). Voegt een menselijke verificatie toe aan de openbare formulieren Abonneren (nieuwsbriefinschrijving) en Lid worden. Laat een van beide sleutels leeg om beide formulieren precies te laten zoals ze nu zijn.','Cloudflare Turnstile secret key'=>'Geheime sleutel voor Cloudflare Turnstile','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'Alleen server-side bewaard — wordt gebruikt om elke formulierinzending direct bij Cloudflare te verifiëren voordat die wordt geaccepteerd.','Email logo'=>'E-maillogo','Email driver'=>'E-maildriver','Artwork submissions address'=>'Adres voor kunstinzendingen','Artists send artwork to this address — e.g. submit@agnosis.art'=>'Kunstenaars sturen kunst naar dit adres — bijv. submit@agnosis.art','Biography submissions address'=>'Adres voor biografie-inzendingen','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'Kunstenaars sturen biografie-updates naar dit adres — bijv. bio@agnosis.art','Event submissions address'=>'Adres voor evenementinzendingen','Artists send event announcements to this address — e.g. event@agnosis.art'=>'Kunstenaars sturen aankondigingen voor evenementen naar dit adres — bijv. event@agnosis.art','Replace artwork address'=>'Adres voor artwork vervangen','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'De kunstenaar stuurt een nieuwe versie van een bestaand artwork. Het onderwerp moet exact overeenkomen met de oorspronkelijke titel. Omzeilt dubbele-detectie — bijvoorbeeld replace@agnosis.art','Removal request address'=>'Adres voor verwijderingsverzoek','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'De kunstenaar vraagt om verwijdering van een bestaand artwork. Het onderwerp moet exact overeenkomen met de titel. Verplaatst de post naar concept in afwachting van controle door een beheerder — bijvoorbeeld remove@agnosis.art','Promote artwork address'=>'Adres om artwork te promoten','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'De kunstenaar stuurt hier een e-mail naartoe (onderwerp = exacte titel van het artwork) om te kiezen welk artwork hen vertegenwoordigt in de gedeelde community-galerij op de hoofdsite — niet hun eigen subdomein, dat al alles toont wat ze hebben gepubliceerd. Elk eerder uitgelicht artwork wordt automatisch gedegradeerd — bijvoorbeeld promote@agnosis.art','Photo-only address'=>'Adres alleen voor foto’s','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'Opt-out-route voor fotografen en lens-gebaseerde kunstenaars van wie de foto het artwork is, niet een snapshot ervan. Inzendingen hier worden gepubliceerd met de originele afbeelding precies zoals verzonden — AI-verrijking wordt overgeslagen en de kwaliteit-afwijscontrole wordt omzeild. AI-beschrijving (titel, tags, alt-tekst) blijft wel draaien. Gebruik de [Photo]-onderwerpaanduiding als fallback voor mailclients die To:-aliassen niet ondersteunen — bijvoorbeeld photo@agnosis.art','Pure address (no AI at all)'=>'Pure adres (helemaal geen AI)','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'Strengste opt-out-route: niets dat hier wordt gestuurd, wordt door AI aangeraakt — geen verrijking, geen visiebeschrijving, geen herschrijving. De gepubliceerde posttitel, body en vertaalde-titel ondertitel worden letterlijk overgenomen uit het onderwerp en de berichttekst van de kunstenaar; het/de bijgevoegde bestand(en) worden precies gepubliceerd zoals ze zijn verzonden. De kwaliteit-afwijscontrole wordt omzeild, net als bij alleen-foto’s. Gebruik de [Pure]-onderwerpaanduiding als fallback voor mailclients die To:-aliassen niet ondersteunen — bijvoorbeeld pure@agnosis.art','Goodbye / self-removal address'=>'Vaarwel / zelfverwijderingsadres','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'De kunstenaar mailt hier naartoe (elk onderwerp, geen bijlage nodig) om accountverwijdering aan te vragen. Er wordt eerst een bevestigingslink teruggestuurd voordat er iets wordt verwijderd — bijvoorbeeld goodbye@agnosis.art','Community announcement address'=>'Adres voor community-aankondigingen','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'Elke actieve kunstenaar mailt hier naartoe (elk onderwerp, geen bijlage nodig) om een bericht naar alle andere communityleden te sturen — bijvoorbeeld community@agnosis.art. Wordt nooit verwerkt als inzending en wordt nooit een post: elke ontvanger krijgt het onderwerp en bericht vertaald naar hun eigen taal, met de naam en het e-mailadres van de afzender erbij zodat ze direct kunnen antwoorden. Verzonden vanaf het adres dat is ingesteld onder Instellingen → Community → Regels, en dat kan anders zijn dan dit adres. Werkt alleen voor een bericht dat is verzonden door een actieve, toegelaten kunstenaar.','IMAP host'=>'IMAP-host','e.g. imap.yourhost.com'=>'bijv. imap.jouwdomein.com','IMAP port'=>'IMAP-poort','Use SSL'=>'SSL gebruiken','Skip SSL certificate validation'=>'SSL-certificaatcontrole overslaan','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ Gebruik dit alleen als tijdelijke oplossing wanneer het certificaat van je mailserver nog niet vertrouwd wordt (bijv. een zelfondertekend Plesk-certificaat vóórdat Let\'s Encrypt op de maildaemon is toegepast). Zet dit uit zodra de mailserver een geldig certificaat presenteert.','IMAP username'=>'IMAP-gebruikersnaam','Login username for the IMAP account — typically the catch-all mailbox address.'=>'Inloggebruikersnaam voor het IMAP-account — meestal het catch-all mailboxadres.','Submission email password'=>'Wachtwoord voor inzendingse-mail','Webhook secret'=>'Webhook-geheim','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'HMAC-geheim gedeeld met je webhook-provider (Mailgun, SendGrid…). Wordt gebruikt voor zowel het inbound-mailendpoint (/wp-json/agnosis/v1/email/inbound) als het bounce-/klachtgebeurtenissen-endpoint (/wp-json/agnosis/v1/email/events) — wijs de bounce/spamklacht-webhook van je provider naar dat laatste om je abonnee- en kunstenaarsadressen schoon te houden.','Inbox retention (days)'=>'Bewaartermijn inbox (dagen)','IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.'=>'IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.','Contact message retention (days)'=>'Bewaartermijn contactberichten (dagen)','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'Contactberichten van bezoeker naar kunstenaar (verzonden of geweigerd) ouder dan deze termijn worden definitief verwijderd door de dagelijkse opschoning. Het IP-adres van de bezoeker wordt los daarvan na 30 dagen gewist, ongeacht deze instelling, zodra het niet meer nuttig is voor misbruikonderzoek. Standaard: 90 dagen.','Per-sender hourly submission limit'=>'Uurlijkse inzendlimiet per afzender','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'Maximaal aantal inzendingen dat van één kunstenaar per uur wordt geaccepteerd, via zowel IMAP als webhook-invoer. Als je deze limiet overschrijdt, wordt het bericht stilletjes gedropt (geen retry door ESP’s). Standaard: 5.','Per-artist contact limit'=>'Contactlimiet per kunstenaar','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'Maximaal aantal berichten dat dezelfde bezoeker (op basis van e-mailadres) binnen het onderstaande venster naar één kunstenaar kan sturen — geldt voor elke taalversie van de pagina van die kunstenaar. Standaard: 2.','Per-artist contact limit window (hours)'=>'Venster voor contactlimiet per kunstenaar (uren)','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'Tijdsvenster, in uren, waarover de bovenstaande contactlimiet per kunstenaar geldt. Bepaalt ook hoe lang een bezoeker de melding "al gecontacteerd" ziet in plaats van het formulier nadat die een kunstenaar heeft gemaild. Standaard: 1 (één uur).','Require SPF/DKIM authentication'=>'SPF/DKIM-authenticatie vereisen','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'Als dit is ingeschakeld, moeten intake-berichten slagen voor SPF- of DKIM-authenticatie (via de Authentication-Results-header). Voorkomt gespoofte From:-adressen. Vereist dat je ESP Authentication-Results-headers meestuurt en dat je domein SPF/DKIM-records heeft ingesteld. Laat uitstaan als je het niet zeker weet — afgewezen legitieme mail is stilletjes. Standaard: uit.','Description provider'=>'Beschrijvingsprovider','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'Analyseert de afbeelding van het artwork en schrijft de titel, body, tags en alt-tekst. WordPress AI Services laat het over aan welke provider de site ook heeft ingesteld via de AI Services-plugin.','OpenAI vision model'=>'OpenAI vision-model','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'Model dat wordt gebruikt voor de beschrijving van het artwork wanneer OpenAI de beschrijvingprovider is. Moet vision-input ondersteunen.','Anthropic model'=>'Anthropic-model','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'Model gebruikt voor de kunstwerkbeschrijving wanneer Anthropic de beschrijvingsprovider is. Moet vision-input ondersteunen.','OpenAI text model'=>'OpenAI text model','Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Anthropic text model'=>'Anthropic text model','Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Vision image max width (px)'=>'Maximale breedte van afbeeldingen voor vision (px)','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'Afbeeldingen worden proportioneel verkleind tot deze breedte voordat ze naar de AI worden gestuurd voor beschrijving — het aantal vision-tokens schaalt mee met de resolutie, en een beschrijvingstaak heeft veel minder pixels nodig dan de originele foto. Geldt voor foto-upload van kunstwerken, gerasterde PDF-pagina\'s en videoposterframes. Stel in op 0 om altijd afbeeldingen in volledige resolutie te versturen (gebruikt meer tokens, geen kwaliteitsverschil bij typische beschrijvingstaken). Vereist de Imagick PHP-extensie; afbeeldingen worden in hun oorspronkelijke grootte verstuurd, ongeacht deze instelling, wanneer die niet beschikbaar is. Standaard: 800.','Enhancement provider'=>'Provider voor verbetering','Auto (OpenAI if key is set)'=>'Automatisch (OpenAI als de sleutel is ingesteld)','Disabled — use original image'=>'Uitgeschakeld — gebruik originele afbeelding','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'Verbetert de afbeelding van het kunstwerk vóór publicatie. Gebruikt OpenAI gpt-image-1. Zet op Uitgeschakeld om verbetering over te slaan en het origineel te publiceren.','OpenAI image model'=>'OpenAI-afbeeldingsmodel','Model used for image enhancement when OpenAI is the enhancement provider.'=>'Model gebruikt voor beeldverbetering wanneer OpenAI de provider voor verbetering is.','Polish biography with AI'=>'Biografie polijsten met AI','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Wanneer ingeschakeld, worden biografie-inzendingen door de AI gehaald om spelling te corrigeren en kleine tekstverbeteringen aan te brengen voordat ze worden opgeslagen.','Polish events with AI'=>'Evenementen polijsten met AI','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Wanneer ingeschakeld, worden evenementinzendingen door de AI gehaald om spelling te corrigeren en kleine tekstverbeteringen aan te brengen voordat ze worden opgeslagen.','Merge biography updates with AI'=>'Biografie-updates samenvoegen met AI','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'Wanneer ingeschakeld, worden biografie-updates met de bestaande biografie samengevoegd met behulp van AI — nieuwe informatie wordt geïntegreerd in plaats van alles te vervangen. Aanbevolen: artiesten kunnen incrementele updates sturen ("Ik heb net een prijs gewonnen") zonder hun volledige bio opnieuw in te sturen. Schakel uit om de biografie altijd te vervangen door de nieuwste inzending.','Rejection threshold (quality score)'=>'Afwijzingsdrempel (kwaliteitscore)','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'Foto’s met een score op of onder deze waarde (1–10) worden automatisch afgekeurd — de artiest ontvangt een vriendelijke e-mail waarin het probleem wordt uitgelegd en wordt uitgenodigd om opnieuw in te sturen. Score 0 schakelt automatische afwijzing uit. Moet lager zijn dan de verbeterdrempel. Standaard: 3.','Enhancement threshold (quality score)'=>'Verbeterdrempel (kwaliteitscore)','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'Foto’s met een score lager dan deze waarde (1–10) worden automatisch verbeterd. Score 10 = perfecte foto, 1 = technisch onbruikbaar. Standaard: 7 — alleen zichtbaar problematische foto’s worden verwerkt. Zet op 1 om automatische verbetering volledig uit te schakelen.','OpenAI API key'=>'OpenAI API-sleutel','Required when OpenAI is the description or enhancement provider.'=>'Vereist wanneer OpenAI de provider voor beschrijving of verbetering is.','Anthropic API key'=>'Anthropic API-sleutel','Required when Anthropic is the description provider.'=>'Vereist wanneer Anthropic de provider voor beschrijving is.','Artwork display width (px)'=>'Weergavebreedte artwork (px)','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'Breedte van de agnosis-artwork-afbeeldingsgrootte die wordt gebruikt in postinhoud en lightbox. De hoogte schaalt proportioneel mee. Standaard: 1920. Bestaande afbeeldingen moeten opnieuw worden gegenereerd nadat je deze waarde wijzigt.','Thumbnail size (px)'=>'Thumbnailgrootte (px)','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'Zijlengte van de vierkante agnosis-thumb-grootte die wordt gebruikt in indieningskaarten en dashboard. Standaard: 512. Bestaande afbeeldingen moeten opnieuw worden gegenereerd nadat je deze waarde wijzigt.','Email image width (px)'=>'E-mailafbeeldingsbreedte (px)','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'Breedte van de agnosis-email-grootte die wordt gebruikt in meldingsmails aan artiesten. De hoogte schaalt proportioneel mee — zonder bijsnijden. Standaard: 420. Bestaande afbeeldingen moeten opnieuw worden gegenereerd nadat je deze waarde wijzigt.','Gallery overview — items per page'=>'Overzicht galerie — items per pagina','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'Hoeveel kunstwerkkaarten het galerie-overzicht per pagina toont. De pool wordt proportioneel opgebouwd over alle artiesten; uitgelichte kunstwerken krijgen voorrang. Standaard: 12.','Review link expiry (days)'=>'Vervaldatum beoordelingslink (dagen)','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'Hoe lang de links Beoordelen & publiceren / Verwijderen in een beoordelingsmail van een inzending geldig blijven voordat een artiest moet inloggen om het item te beheren. Geldt uniform voor concepten van kunstwerken, biografie en evenementen. Standaard: 7.','System prompt'=>'Systeemprompt','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'Gestuurd naar de AI als systeeminstructie. Gebruik {tag_count} en {excerpt_words} als tokens — ze worden vervangen door de waarden hieronder.','Artist prompt template'=>'Sjabloon voor artiestprompt','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'Gebruikersbericht dat samen met de afbeelding van het kunstwerk wordt verstuurd. Gebruik {artist_prompt} waar de eigen beschrijving van de artiest moet staan.','Enhancement instructions'=>'Verbeterinstructies','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'Instructies die naar de provider voor beeldverbetering worden gestuurd. De door AI gegenereerde beschrijving van het kunstwerk wordt automatisch toegevoegd als context.','Number of tags'=>'Aantal tags','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'Hoeveel tags de AI per kunstwerk moet genereren. Wordt in de systeemprompt weergegeven als {tag_count}.','Excerpt word limit'=>'Woordenlimiet voor fragment','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'Maximaal aantal woorden voor het fragment van één zin. Wordt in de systeemprompt weergegeven als {excerpt_words}.','Trust all admitted artists (skip link review entirely)'=>'Vertrouw alle toegelaten artiesten (review van links volledig overslaan)','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'Elke artiest hier is al door de community aanbevolen — als dat vertrouwen voor jou genoeg is, zet dit aan om elke link die een artiest indient meteen in te sluiten, zonder allowlist-controle en zonder enige AI-review (de onderstaande instellingen worden dan volledig overgeslagen). Standaard uit. Schakel dit alleen in als je het prima vindt dat een kwaadwillende die door de toelating is gekomen een link naar eender wat kan insluiten.','Trusted embed platforms'=>'Vertrouwde embedplatforms','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'Eén hostnaam per regel. Een ingediende link wordt meteen een rijke embed als die overeenkomt met een van deze hostnamen (of een subdomein daarvan) — geen AI-review nodig, en er wordt geen netwerkverzoek naar de link zelf gedaan.','Let artists submit other links too (AI-reviewed)'=>'Laat artiesten ook andere links indienen (AI-beoordeeld)','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'Wanneer ingeschakeld, wordt een link naar een site die niet op de vertrouwde lijst hierboven staat niet gewoon weggegooid: de bestemmingspagina wordt opgehaald en beoordeeld door je ingestelde AI-provider (Instellingen → AI-providers) aan de hand van de categorieën hieronder voordat wordt besloten of deze wordt ingesloten. Als de AI niet bereikbaar is, de aanvraag time-out krijgt of de pagina niet veilig kan worden opgehaald, wordt de link niet ingesloten — dan faalt het veilig. Wanneer uitgeschakeld (de standaard), worden alleen de vertrouwde platforms hierboven ooit ingesloten.','Block pornographic / sexually explicit content'=>'Pornografische / seksueel expliciete content blokkeren','Only takes effect when AI review (above) is enabled.'=>'Heeft alleen effect wanneer AI-beoordeling (hierboven) is ingeschakeld.','Block primarily commercial / promotional sites'=>'Voornamelijk commerciële / promotionele sites blokkeren','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'Webwinkels, advertenties, landingspagina’s voor marketing. Standaard uit — een artiest die naar een shop linkt die zijn eigen prints verkoopt, komt vaak voor en is niet per se ongewenst. Heeft alleen effect wanneer AI-beoordeling (hierboven) is ingeschakeld.','Block gambling / betting sites'=>'Gok- / wedsites blokkeren','Additional disallowed categories'=>'Aanvullende niet-toegestane categorieën','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'Optioneel — beschrijf in gewone taal elk ander soort content dat de AI moet afwijzen (bijv. "haatzaaien of gewelddadige extremistische content", "phishing- of scam-pagina\'s"). Heeft alleen effect wanneer AI-beoordeling (hierboven) is ingeschakeld.','Node label'=>'Node-label','How this node introduces itself to the network.'=>'Hoe deze node zichzelf aan het netwerk voorstelt.','Enable ActivityPub federation'=>'ActivityPub-federatie inschakelen','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'Nieuwe kunstwerken uitzenden naar Mastodon, Pixelfed en de Fediverse.','Node public key'=>'Publieke nodesleutel','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'Automatisch gegenereerde RSA-publieke sleutel voor deze node. Deel deze met peernodes.','Self-removal (goodbye) requests per sender per day'=>'Aantal verzoeken om zelfverwijdering (afscheid) per afzender per dag','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'Maximaal aantal bevestigingsmails voor zelfverwijdering („afscheid”) dat één afzenderadres per dag kan triggeren. Een echte zelfverwijdering hoeft maar één keer aangevraagd te worden — dit begrenst hoeveel bevestigingsmails een vervalst of herhaald Van:-adres kan gebruiken om een echte artiest te spammen. Standaard: 3.','Community broadcasts per artist per day'=>'Aantal community-broadcasts per artiest per dag','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'Maximaal aantal berichten dat één artiest per dag naar het community-aankondigingsadres kan sturen (Instellingen → E-mail). Voorkomt dat één lid de inbox van alle andere leden overspoelt. Standaard: 3.','Community broadcast max length (characters)'=>'Maximale lengte van community-broadcasts (tekens)','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'Langere berichten naar het community-aankondigingsadres worden teruggestuurd naar de afzender in plaats van uitgezonden — de afzender wordt verteld het bericht korter te maken en opnieuw te verzenden. Gemeten in tekens, niet in woorden, zodat het eerlijk werkt voor talen zonder spaties tussen woorden (Chinees, Japans, Thai, enz.). Elke kopie voor een ontvanger wordt apart vertaald, dus dit begrenst ook hoeveel één bericht kan kosten aan AI-vertaalverzoeken. Standaard: 2000. Harde maximum: 20000, ongeacht deze instelling.','Admission vote threshold (%)'=>'Drempel voor toelatingsstemming (%)','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'Percentage actieve artiesten dat ja moet stemmen voor toelating. Gecombineerd met de minimale ondergrens hieronder.','Admission minimum votes'=>'Minimaal aantal stemmen voor toelating','Absolute minimum positive votes required regardless of the percentage above.'=>'Absoluut minimum aantal positieve stemmen dat vereist is, ongeacht het percentage hierboven.','Voting window (days)'=>'Stemvenster (dagen)','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'Aantal dagen dat een aanvraag open blijft. Als de drempel niet binnen dit venster wordt gehaald, wordt de aanvraag afgewezen.','Resolved application retention (days)'=>'Bewaartermijn van afgehandelde aanvragen (dagen)','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'E-mail, naam, biografie, verklaring en portfolio-link van een afgewezen, ingetrokken of vertrokken aanvraag worden na dit aantal dagen geanonimiseerd door de dagelijkse opschoning — de aanvraag zelf (status en data) blijft bewaard voor de toelatingsgeschiedenis. De biografie/verklaring/portfolio van een gebande artiest worden volgens hetzelfde schema geanonimiseerd, maar hun e-mailadres blijft expres bewaard zodat het verbod gehandhaafd kan blijven. Standaard: 180 dagen.','After applying, send artists to'=>'Stuur artiesten na aanmelding naar','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'Optioneel — kies een pagina die het vouwing-proces en wat er daarna gebeurt uitlegt. Wanneer de aanvraag succesvol is verzonden, wordt de artiest daarheen doorgestuurd in plaats van alleen een bevestigingsbericht binnen de pagina te zien. Laat op "Geen" staan om alleen het inline bericht te behouden.','Community size cap'=>'Capaciteitslimiet van de community','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'Maximaal aantal toegelaten artiesten. Als de community vol is, komen nieuwe aanvragen op een wachtlijst in plaats van te worden afgewezen, en een vrijgekomen plek laat de volgende in de rij toe. Zet op 0 voor geen limiet. De community kan dit ook per stemming wijzigen.','Cap-change co-signers required'=>'Aantal mede-ondertekenaars vereist voor capwijziging','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'Hoeveel artiesten een voorstel moeten mede-ondertekenen om de capaciteitslimiet van de community te wijzigen voordat het opent als een volledige communitystemming.','Cap-change vote window (days)'=>'Stemvenster voor capwijziging (dagen)','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'Aantal dagen dat een stemming over een capwijziging open blijft. Een strikte meerderheid van actieve artiesten die ja stemmen, voert de nieuwe cap in.','Removal nominations required'=>'Vereiste nominaties voor verwijdering','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'Aantal artiestennominaties dat nodig is voordat een communitystemming over verwijdering opent. Beheerders kunnen deze drempel omzeilen.','Removal vote window (days)'=>'Stemvenster voor verwijdering (dagen)','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'Aantal dagen dat een communitystemming over verwijdering open blijft. Een meerderheid (>50%) van de actieve artiesten moet ja stemmen om verwijdering door te laten gaan.','Invitation intro'=>'Intro voor uitnodiging','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis is een kleine, zelf gehoste thuisbasis voor artiesten die liever maken dan een platform beheren. Er is geen algoritme dat beslist wie je kunst ziet, geen portfoliosite om bij te houden en geen account om in te stellen — alleen je werk, automatisch gepubliceerd en vertaald voor een wereldwijd publiek.

Deel uitmaken van de community is simpel: andere artiesten dragen nieuwe aanmelders voor, en iedereen behoudt volledig eigendom van wat ze publiceren; je kunt op elk moment vertrekken en je werk meenemen.

Zodra je bent toegelaten, dien je nieuw werk in door het als een e-mail te sturen — geen dashboard, geen formulieren en je kunt je kunstwerk ook bijwerken, promoten of verwijderen door een e-mail te sturen. Meer informatie vind je op de website agnosis.art.','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'Wordt bovenaan de onderstaande e-mail "Uitnodiging versturen" getoond (er volgt automatisch een link "Aanmelden" en de sitenaam — die hoef je hier niet toe te voegen). Twee of drie korte alinea\'s is genoeg. Statische tekst, wordt na gebruik niet gewist zoals de nieuwsbrief-intro\'s hierboven — wordt automatisch vertaald wanneer een uitnodiging in een andere taal dan die van de site wordt verstuurd.','Transaction fee (%)'=>'Transactiekosten (%)','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'Percentage dat deze node inhoudt op donaties en kunstverkopen. Artiesten betalen vooraf niets.','Sender name'=>'Afzendernaam','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'Naam die wordt getoond als afzender van digestmails. Laat leeg om de sitenaam te gebruiken.','Sender email address'=>'E-mailadres van afzender','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Specifiek From:-adres voor beide nieuwsbrieven, bijv. newsletter@agnosis.art — houdt digestmail gescheiden van de admin-e-mail van de site voor betere bezorging en zodat artiesten het kunnen filteren. Laat leeg om het admin-e-mailadres te gebruiken. Moet een geldig, bezorgbaar adres op je domein zijn (SPF/DKIM geconfigureerd) of berichten kunnen als spam worden gemarkeerd.','Auto-draft newsletter intros'=>'Nieuwsbrief-intro’s automatisch als concept opstellen','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'Als dit is ingeschakeld, maakt Agnosis via AI voorafgaand aan elk nummer een intro als concept (zie de doorlooptijd hieronder), slaat die op in het intro-veld van die nieuwsbrief en mailt jou om het te beoordelen — tenzij je er voor die cyclus al zelf een hebt geschreven. Schakel uit om beide intro-velden exact te laten zoals je ze hebt gelaten, altijd.','Draft intro this many hours ahead'=>'Stel deze intro zoveel uur van tevoren als concept op','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'Hoe lang voordat een nummer moet verschijnen Agnosis een door AI opgesteld intro voorstelt. Heeft alleen effect wanneer het automatisch opstellen van concepten (hierboven) is ingeschakeld. Standaard: 24.','Artist newsletter'=>'Artiestennieuwsbrief','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'Toegelaten artiesten worden automatisch aangemeld (ze kunnen zich met één klik afmelden voor elk nummer). Communitydigest: recente activiteit, nieuwe leden, open stemmen.','Artist newsletter frequency (days)'=>'Frequentie van de artiestennieuwsbrief (dagen)','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'Standaard 30 ≈ maandelijks. Er wordt een nieuw nummer voorbereid zodra er zoveel dagen zijn verstreken sinds het laatste nummer is verstuurd.','Artist newsletter intro'=>'Intro van de artiestennieuwsbrief','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Optionele noot die alleen vóór het volgende kunstenaarsnummer wordt geplaatst — wordt automatisch verwijderd zodra dat nummer in de wachtrij staat. Laat leeg om de auto-digest zonder intro te versturen. Als je dit leeg laat, maakt Agnosis er automatisch ongeveer een dag voordat het nummer wordt verstuurd een concept van op basis van wat er nieuw is, en mailt je om het eerst te beoordelen — schrijf hier op elk moment je eigen tekst om dat over te slaan.','Public newsletter'=>'Openbare nieuwsbrief','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'Bezoekers schrijven zich in via het agnosis/newsletter-signup-blok (dubbele opt-in). Digest: nieuwe kunstwerken en evenementen die zijn gepubliceerd sinds het vorige nummer.','Public newsletter frequency (days)'=>'Frequentie van de openbare nieuwsbrief (dagen)','Default 30 ≈ monthly.'=>'Standaard 30 ≈ maandelijks.','Public newsletter intro'=>'Intro voor openbare nieuwsbrief','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Optionele noot die alleen vóór het volgende openbare nummer wordt geplaatst — wordt automatisch verwijderd zodra dat nummer in de wachtrij staat. Als je dit leeg laat, maakt Agnosis er automatisch ongeveer een dag voordat het nummer wordt verstuurd een concept van op basis van wat er nieuw is, en mailt je om het eerst te beoordelen — schrijf hier op elk moment je eigen tekst om dat over te slaan.','Send batch size'=>'Batchgrootte voor verzenden','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'Aantal ontvangers dat per cron-tick van 5 minuten wordt gemaild. Verlaag dit als je host uitgaande mail afknijpt; verhoog het voor snellere bezorging op hosts met royale limieten.','Self-hosting comfort threshold'=>'Drempel voor zelf hosten','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'Alleen ter advisering — zelf gehost versturen blijft werken boven dit aantal. Zodra het bevestigde aantal openbare abonnees erboven komt, laat deze pagina een herinnering zien om in plaats daarvan een e-mailserviceprovider te overwegen (bijv. de gratis laag van Brevo).','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'Stuurt een minimale ping ("Antwoord met het woord: ping") met de geconfigureerde API-sleutel.','Sends a minimal ping using the configured API key.'=>'Stuurt een minimale ping met de geconfigureerde API-sleutel.','WordPress AI Client'=>'WordPress AI-client','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'Controleert of wp_ai_client_prompt() beschikbaar is (WordPress 7.0+) en of er een tekstgeneratiemodel is geconfigureerd.','Test AI Providers'=>'AI-providers testen','Test %s'=>'Test %s','Bot Protection'=>'Botbescherming','Turnstile is configured.'=>'Turnstile is geconfigureerd.','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'Het aanmeldingsformulier Join en het formulier voor nieuwsbriefinschrijving vereisen allebei menselijke verificatie voordat ze een inzending accepteren.','Turnstile is not configured.'=>'Turnstile is niet geconfigureerd.','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'Je Join-aanmeldingsformulier is openbaar — iedereen kan een aanmelding insturen, en een ingestuurde (en bevestigde) aanmelding mailt nog steeds elke toegelaten artiest en admin. Op dit moment is het enige dat tussen dat formulier en een geautomatiseerde bot staat een vaste limiet van 5 inzendingen per minuut per IP, die een gedistribueerde bot volledig kan omzeilen. Voeg hierboven een Cloudflare Turnstile-sitesleutel en geheime sleutel toe om menselijke verificatie te vereisen op zowel het Join-formulier als het formulier voor nieuwsbriefinschrijving.','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'AI-verwerking & privacybeleid','A Privacy Policy page is set.'=>'Er is een Privacybeleid-pagina ingesteld.','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'Er is automatisch voorgestelde formulering toegevoegd die %s en openbare federatie dekt — bekijk die onder Instellingen → Privacy → "Handleiding" voordat je publiceert, en check bij je provider(s) hun eigen gegevensverwerkingsovereenkomst (DPA) voor je nalevingsverplichtingen.','No Privacy Policy page is set.'=>'Er is geen Privacybeleid-pagina ingesteld.','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'Ingezonden kunstwerken, tekst en contactberichten van bezoekers worden voor verwerking naar %s gestuurd. Maak een pagina aan of kies er een onder Instellingen → Privacy — deze plugin heeft daar al voorgestelde formulering voor klaargezet die je onder "Handleiding" vindt. Misschien wil je ook die provider z\'n gegevensverwerkingsovereenkomst (DPA) bekijken voor je eigen nalevingsverplichtingen.','Go to Settings → Privacy'=>'Ga naar Instellingen → Privacy','Debug Files'=>'Debugbestanden','Currently'=>'Momenteel','Enabled'=>'Ingeschakeld','Disabled'=>'Uitgeschakeld','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'Geforceerd AAN door de AGNOSIS_DEBUG-constante in wp-config.php — het selectievakje hierboven heeft geen effect totdat die regel wordt verwijderd.','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'Geforceerd UIT door de AGNOSIS_DEBUG-constante in wp-config.php — het selectievakje hierboven heeft geen effect totdat die regel wordt verwijderd.','Directory'=>'Map','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'Filter met agnosis_debug_dir om debug-uitvoer elders naartoe te leiden.','.txt file(s) in the directory'=>'.txt-bestand(en) in de map','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'Alle .txt-bestanden in de debugmap verwijderen? De map zelf blijft bestaan zodat toekomstige debugschrijvingen nog steeds netjes daar terechtkomen.','Clear Debug Files'=>'Debugbestanden wissen','Term Translation Cache'=>'Termvertaalcache','Cached translations'=>'Gecachte vertalingen','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'Door AI vertaalde termnamen voor tags/media, gecached zodat dezelfde term altijd hetzelfde vertaalde label krijgt in plaats van per bericht een nieuwe AI-formulering. Het hernoemen van een term wist diens eigen gecachte item al automatisch; gebruik de knop hieronder alleen als een gecachte vertaling zelf onjuist is.','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'Alle gecachte termvertalingen wissen? Er wordt niets van je site verwijderd — termen worden gewoon de volgende keer dat ze nodig zijn opnieuw door AI vertaald.','Clear Term Translation Cache'=>'Termvertaalcache wissen','Pipeline Logs'=>'Pijplijnlogboeken','Clear all log entries?'=>'Alle logregels wissen?','Clear All'=>'Alles wissen','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'Totaal %d regels. Logboeken worden automatisch opgeschoond op basis van de Inbox-bewaarinstelling.','No log entries yet.'=>'Nog geen logregels.','Time'=>'Tijd','Level'=>'Niveau','Context'=>'Context','Inbox Tools'=>'Inbox-tools','Test connection'=>'Verbinding testen','Test IMAP Connection'=>'IMAP-verbinding testen','Connects to the configured mailbox and reports the total and unseen message count.'=>'Maakt verbinding met de geconfigureerde mailbox en geeft het totaal aantal berichten en het aantal ongelezen berichten weer.','Poll inbox now'=>'Inbox nu ophalen','Poll Inbox Now'=>'Inbox nu ophalen','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'Haalt ongelezen berichten meteen op zonder op WP-Cron te wachten. Klik daarna op "Wachtrij met openstaande items verwerken" om de AI-pijplijn uit te voeren.','Process queue'=>'Wachtrij verwerken','Process Pending Queue'=>'Wachtrij met openstaande items verwerken','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'Voert de AI-pijplijn meteen uit op alle openstaande wachtrij-items, zonder op WP-Cron te wachten. Gebruik dit om de volledige flow na een poll te testen.','Force reprocess'=>'Opnieuw verwerken forceren','Force Reprocess Inbox'=>'Inbox opnieuw verwerken forceren','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'Zet mislukte/vastgelopen/wees-wachtrijrijen terug naar openstaand en haalt daarna meteen onbewerkte berichten op. Klik daarna op "Wachtrij met openstaande items verwerken" om de AI-pijplijn uit te voeren. Kunstwerken die al gepubliceerd zijn met geldige berichten worden nooit opnieuw verwerkt.','Send Test'=>'Test verzenden','Deliverability'=>'Afleverbaarheid','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'Alleen een diagnostische controle — hier verandert niets aan hoe mail wordt verzonden. Op gewone hosting (PHP mail(), geen SMTP-plugin) is mail die wordt verzonden vanaf een adres dat niet overeenkomt met het eigen domein van je site, of vanaf een domein zonder SPF/DMARC-record, steeds waarschijnlijker om in spam te belanden of volledig te worden geweigerd door grote mailboxproviders. Als hieronder een regel er verkeerd uitziet, is de meest betrouwbare oplossing het installeren van een SMTP-verzendplugin (WP Mail SMTP, Post SMTP, FluentSMTP en andere werken allemaal) die is ingesteld op een echte transactionele mailprovider, en het toevoegen van SPF/DMARC-records voor het domein waarvan je verzendt bij je DNS-host.','From identity'=>'Afzenderidentiteit','Domain matches site?'=>'Komt het domein overeen met de site?','SPF record'=>'SPF-record','DMARC record'=>'DMARC-record','SMTP plugin'=>'SMTP-plugin','Detected: %s'=>'Gedetecteerd: %s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'Er zijn geen van de gangbare SMTP-verzendplugins gedetecteerd — deze site gebruikt waarschijnlijk de ingebouwde PHP mail(), die door de meeste hosts slecht wordt afgeleverd.','Send a real test email to:'=>'Stuur een echte testmail naar:','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'Verzendt één platte-tekstmail vanaf dezelfde community-identiteit die wordt gebruikt voor review-/stem-/vouch-mail. Als die in je inbox aankomt, is dat een goed teken; als die in spam belandt of helemaal niet aankomt, bevestigt dat een echt afleverprobleem, ongeacht wat de controles hierboven zeggen.','Found'=>'Gevonden','Not found'=>'Niet gevonden','DNS lookup failed'=>'DNS-opzoeking mislukt','Unavailable on this host'=>'Niet beschikbaar op deze host','No address configured'=>'Geen adres geconfigureerd','[TEST] Deliverability check from %s'=>'[TEST] Afleverbaarheidstest van %s','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'Dit is een eenmalige afleverbaarheidstest vanaf je Agnosis-instellingen → e-mailinboxpagina. Als je dit in je inbox leest (niet in spam), dan is de community-/transactionele afzenderidentiteit leverbaar naar dit adres.','Pending Applications'=>'Openstaande aanvragen','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d aanvraag wacht nog op e-mailbevestiging van de aanvrager en staat daarom nog niet hieronder vermeld.' . "\0" . '%d aanvragen wachten nog op e-mailbevestiging van de aanvrager en staan daarom nog niet hieronder vermeld.','No pending applications.'=>'Geen openstaande aanvragen.','%d positive vote(s) currently required for admission.'=>'Er zijn momenteel %d positieve stemmen nodig voor toelating.','Applicant'=>'Aanvrager','Applied'=>'Aangevraagd','Votes'=>'Stemmen','Bio / Portfolio'=>'Bio / portfolio','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'Portfolio ↗','Admit'=>'Toelaten','Reject'=>'Afwijzen','No admitted members yet.'=>'Nog geen toegelaten leden.','Joined'=>'Aangesloten','Banned until %s'=>'Verbannen tot %s','Banned'=>'Verbannen','Active'=>'Actief','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'Dit adres heeft gebounced of is als spam gemeld — mogelijk bereikt mail deze kunstenaar niet meer.','⚠ %d bounce'=>'⚠ %d bounce' . "\0" . '⚠ %d bounces','This artist has muted community broadcast messages.'=>'Deze kunstenaar heeft community-uitzendberichten gedempt.','🔇 Broadcasts muted'=>'🔇 Uitzendingen gedempt','This artist receives one daily digest of open applications instead of an email per application.'=>'Deze kunstenaar ontvangt één dagelijkse samenvatting van open aanmeldingen in plaats van een e-mail per aanmelding.','📬 Vote digest mode'=>'📬 Stem-samenvattingsmodus','Leave the date blank to ban indefinitely. Continue?'=>'Laat de datum leeg om voor onbepaalde tijd te verbannen. Doorgaan?','Leave blank to ban indefinitely'=>'Laat leeg om voor onbepaalde tijd te verbannen','Suspend'=>'Schorsen','Permanently delete this artist and all their content? This cannot be undone.'=>'Deze kunstenaar en al hun content permanent verwijderen? Dit kan niet ongedaan worden gemaakt.','Open a community removal vote for this artist? All members will be emailed.'=>'Een gemeenschapsstemronde openen om deze kunstenaar te verwijderen? Alle leden krijgen een e-mail.','Open Vote'=>'Stemronde openen','Newsletter Status'=>'Status nieuwsbrief','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'Je hebt %1$d bevestigde openbare abonnees, boven de ingestelde comfortdrempel van %2$d. Zelf gehost verzenden werkt nog steeds, maar je wilt misschien een e-mailserviceprovider koppelen (bijv. het gratis abonnement van Brevo) voor een betere afleverbaarheid op deze schaal.','Audience'=>'Doelgroep','Last sent'=>'Laatst verzonden','Action'=>'Actie','Failed recipients'=>'Mislukte ontvangers','Send a test'=>'Verstuur een test','%1$d admitted (%2$d opted out)'=>'%1$d toegelaten (%2$d afgemeld)','Sending…'=>'Bezig met verzenden…','Idle'=>'Inactief','Send Now'=>'Nu verzenden','Public'=>'Openbaar','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d bevestigd, %2$d wacht op bevestiging, %3$d uitgeschreven, %4$d gebounced','By language: %s'=>'Per taal: %s','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'Voeg het blok "Nieuwsbriefaanmelding" toe aan elke pagina zodat bezoekers zich kunnen abonneren op de openbare nieuwsbrief. Kunstenaars worden automatisch ingeschreven en kunnen zich met één klik afmelden van elk nummer.','Never'=>'Nooit','Unknown'=>'Onbekend','None'=>'Geen','%d failed'=>'%d mislukt' . "\0" . '%d mislukt','Retry Failed'=>'Mislukte opnieuw proberen','Invite an Artist'=>'Een kunstenaar uitnodigen','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'Verstuur een eenmalige e-mail om iemand uit te nodigen om zich aan te melden. Er wordt niets bijgehouden of gepland — dit wordt meteen verstuurd naar het onderstaande adres.','artist@example.com'=>'artist@example.com','Send Invitation'=>'Uitnodiging versturen','Permission denied.'=>'Toestemming geweigerd.','OpenAI API key not configured.'=>'OpenAI API-sleutel niet geconfigureerd.','OpenAI connection successful.'=>'Verbinding met OpenAI geslaagd.','Anthropic API key not configured.'=>'Anthropic API-sleutel niet geconfigureerd.','Anthropic connection successful.'=>'Verbinding met Anthropic geslaagd.','WordPress AI Client requires WordPress 7.0 or later.'=>'WordPress AI Client vereist WordPress 7.0 of later.','No text-generation model configured. Set one up under Settings → Connectors.'=>'Er is geen tekstgeneratiemodel geconfigureerd. Stel er een in onder Instellingen → Koppelingen.','WordPress AI Client is available and a text-generation model is configured.'=>'WordPress AI Client is beschikbaar en er is een tekstgeneratiemodel geconfigureerd.','Unknown provider.'=>'Onbekende provider.','HTTP %d'=>'HTTP %d','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'De kunstenaar heeft geen onderwerpregel of bericht meegestuurd met deze inzending — laat het beeld volledig voor zichzelf spreken.','Name'=>'Naam','Bio'=>'Bio','Statement'=>'Statement','%1$s must be %2$d characters or fewer.'=>'%1$s mag %2$d tekens of minder zijn.','Please select your language.'=>'Selecteer je taal.','An account with this email address already exists.'=>'Er bestaat al een account met dit e-mailadres.','This email address belongs to an admitted artist.'=>'Dit e-mailadres hoort bij een toegelaten kunstenaar.','An application for this email address is already pending.'=>'Er is al een aanvraag in behandeling voor dit e-mailadres.','Application not found.'=>'Aanvraag niet gevonden.','Only admitted artists can vouch.'=>'Alleen toegelaten kunstenaars kunnen aanbevelingen doen.','Admin access required.'=>'Admin-toegang vereist.','You cannot vote on your own application.'=>'Je kunt niet op je eigen aanvraag stemmen.','Invalid or incomplete link.'=>'Ongeldige of onvolledige link.','This confirmation link is invalid or has already been used.'=>'Deze bevestigingslink is ongeldig of is al gebruikt.','Confirm your application?'=>'Je aanvraag bevestigen?','Your application will open for community review once you confirm below.'=>'Je aanvraag wordt opengezet voor review door de community zodra je hieronder bevestigt.','Confirm my application'=>'Mijn aanvraag bevestigen','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'Deze community is momenteel vol, dus je aanvraag is op de wachtlijst gezet — wanneer een lid vertrekt, wordt de volgende in de rij toegelaten.','You\'re all set — the community can now review your application and vote.'=>'Alles is geregeld — de community kan je aanvraag nu beoordelen en stemmen.','Application confirmed'=>'Aanvraag bevestigd','Thanks, %s!'=>'Dank je, %s!','Link error'=>'Linkfout','Confirm your application to %s'=>'Bevestig je aanvraag voor %s','Your application to %s'=>'Je aanvraag voor %s','Application by %s has closed'=>'Aanvraag van %s is gesloten','Welcome to %s'=>'Welkom bij %s','We received your application to %s'=>'We hebben je aanvraag voor %s ontvangen','Hi %s,'=>'Hoi %s,','One last step before %s can review your application: confirm this is really your email address.'=>'Nog één stap voordat %s je aanvraag kan beoordelen: bevestig dat dit echt je e-mailadres is.','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'Als je niet hebt aangevraagd, negeer deze e-mail dan gewoon — er gebeurt niets totdat op deze link wordt geklikt.','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'Dank je voor je aanvraag voor %s. Je aanvraag is ontvangen en staat nu open voor review door de community.','The community has %d days to vote. We will let you know the outcome by email.'=>'De community heeft %d dagen om te stemmen. We laten je per e-mail weten wat de uitkomst is.','New application: %1$s wants to join %2$s'=>'Nieuwe aanvraag: %1$s wil lid worden van %2$s','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'%1$s heeft zich aangemeld om lid te worden van %2$s. Je hebt %3$d dagen om te stemmen.','Portfolio:'=>'Portfolio:','Vote YES'=>'Stem JA','Vote NO'=>'Stem NEE','You can change your vote at any time within the voting window.'=>'Je kunt je stem op elk moment binnen de stemperiode wijzigen.','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'Dank je voor je aanvraag voor %s. Helaas heeft je aanvraag niet genoeg stemmen gekregen binnen de stemperiode.','You are welcome to apply again in the future.'=>'Je bent welkom om je in de toekomst opnieuw aan te melden.','The application by %s has closed without reaching the admission threshold. No action required.'=>'De aanvraag van %s is gesloten zonder de toegangsgrens te halen. Geen verdere actie nodig.','The %s community has admitted you as an artist. Welcome!'=>'De %s-community heeft je toegelaten als kunstenaar. Welkom!','Your gallery:'=>'Je galerij:','Your submissions:'=>'Je inzendingen:','How to share your work — send an email to:'=>'Hoe je je werk deelt — stuur een e-mail naar:','Subject line conventions:'=>'Onderwerprichtlijnen:','Artwork (default) — any subject'=>'Artwork (standaard) — elk onderwerp','[Biography] — biography update'=>'[Biografie] — biografie-update','[Event] — event announcement'=>'[Evenement] — aankondiging van een evenement','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[Foto] — publiceer zoals het is, zonder AI-verrijking (terugval voor mailapps zonder To:-aliassen)','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[Zuiver] — publiceer exact zoals verzonden, zonder enige AI (terugval voor mailapps zonder To:-aliassen)','To leave the network and delete your account:'=>'Om het netwerk te verlaten en je account te verwijderen:','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'Stuur gewoon een e-mail (geen bijlage nodig). Je ontvangt een bevestigingslink — er wordt niets verwijderd totdat je daarop klikt.','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'Er is geen login nodig om met Agnosis te werken — alles hierboven gebeurt via e-mail. Als je ook de optionele online functies van de site wilt gebruiken (zoals een inzending bekijken voordat die wordt gepubliceerd), kun je altijd een wachtwoord instellen met','password recovery'=>'wachtwoordherstel','Submit artwork'=>'Artwork insturen','Submit biography'=>'Biografie insturen','Submit event'=>'Evenement insturen','Replace artwork (subject: exact title)'=>'Artwork vervangen (onderwerp: exacte titel)','Remove artwork (subject: exact title)'=>'Artwork verwijderen (onderwerp: exacte titel)','Feature artwork in the shared gallery (subject: exact title)'=>'Artwork uitlichten in de gedeelde galerij (onderwerp: exacte titel)','Photo-only — publish as-is, no AI enhancement'=>'Alleen foto — publiceer zoals het is, zonder AI-verrijking','Pure — publish exactly as sent, no AI at all'=>'Zuiver — publiceer exact zoals verzonden, zonder enige AI','About %s'=>'Over %s','%1$s — %2$s'=>'%1$s — %2$s','[%s] Your community message was not sent — too long'=>'[%s] Je communitybericht is niet verzonden — te lang','[%s] Your community message was not sent — no content found'=>'[%s] Je communitybericht is niet verzonden — geen inhoud gevonden','[%1$s] Community message from %2$s'=>'[%1$s] Communitybericht van %2$s','%1$s <%2$s> sent a message to the community:'=>'%1$s <%2$s> heeft een bericht naar de community gestuurd:','Subject: %s'=>'Onderwerp: %s','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'Druk op beantwoorden om te reageren — je antwoord gaat terug naar de hele community, automatisch vertaald, net als dit bericht.','This message was sent by %s.'=>'Dit bericht is verzonden door %s.','%1$s via %2$s'=>'%1$s via %2$s','no limit'=>'geen limiet','Community size-cap vote open at %s'=>'Stemming over communitygrootte-limiet geopend bij %s','Community size cap changed at %s'=>'Communitygrootte-limiet gewijzigd bij %s','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'De community heeft gestemd om de limiet voor de lidmaatschapsomvang te wijzigen naar %1$s (voorstel #%2$d). De nieuwe limiet is nu van kracht.','Community size-cap proposal did not pass at %s'=>'Voorstel voor communitygrootte-limiet is niet aangenomen bij %s','Only community members can do this.'=>'Alleen communityleden kunnen dit doen.','The cap must be zero or a positive number.'=>'De limiet moet nul of een positief getal zijn.','That is already the current cap.'=>'Dat is al de huidige limiet.','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'Er loopt al een ander limietvoorstel. Los dat eerst op of co-onderteken dat eerst.','No active proposal to co-sign.'=>'Er is geen actief voorstel om mee te ondertekenen.','Proposal not found.'=>'Voorstel niet gevonden.','This vote is not currently open.'=>'Deze stemming is momenteel niet open.','This artist can\'t be reached through this form right now.'=>'Deze kunstenaar is op dit moment niet via dit formulier bereikbaar.','Thanks — your message has been sent.'=>'Bedankt — je bericht is verzonden.','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'Spam, oplichting of ongevraagde commerciële reclame die niets te maken heeft met de kunstenaar echt contacteren over diens werk','Flagged by automatic content review.'=>'Gemarkeerd door automatische inhoudscontrole.','New message from %s via your Agnosis contact form'=>'Nieuw bericht van %s via je Agnosis-contactformulier','From: %s'=>'Van: %s','(no name provided)'=>'(geen naam opgegeven)','Original message, as submitted:'=>'Oorspronkelijk bericht, zoals ingediend:','Your name (optional)'=>'Je naam (optioneel)','Your email address'=>'Je e-mailadres','you@example.com'=>'jou@voorbeeld.com','Send message'=>'Bericht verzenden','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'Bedankt — je bericht is verzonden. Je kunt later opnieuw contact opnemen met deze kunstenaar.','Something went wrong. Please try again.'=>'Er is iets misgegaan. Probeer het opnieuw.','Authentication required.'=>'Aanmelding vereist.','This field cannot be edited here.'=>'Dit veld kan hier niet worden bewerkt.','That date could not be understood.'=>'Die datum kon niet worden begrepen.','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'Dat lijkt geen geldige tijdzone te zijn (bijv. "Europe/Madrid").',